{
  "name": "finish",
  "version": "1.0.0",
  "description": "Autonomous task completion: lint → test → commit → push. Run this when you are done with any task. Never ask the user to commit or push — just run this skill.",
  "trigger": {
    "on_event": "task_complete",
    "manual": true
  },
  "commands": {
    "finish": "Lint, test, commit with message, and push to origin/main"
  },
  "inputs": [
    {
      "name": "MESSAGE",
      "description": "Conventional commit message describing what was done (e.g. 'feat(api): add user auth endpoint')",
      "required": true
    },
    {
      "name": "SKIP_TESTS",
      "description": "Set to 'true' to skip tests (use only if tests are not yet written for the changed code)",
      "required": false
    }
  ],
  "outputs": [
    {
      "type": "text",
      "description": "Git push confirmation with commit SHA and branch"
    }
  ],
  "required_tools": ["git"],
  "estimated_duration": "30-120s",
  "risk_level": "medium",
  "notes": [
    "This is the MANDATORY final step of every task.",
    "Lint failures are auto-fixed then re-staged before committing.",
    "Test failures abort the push — fix the tests first.",
    "Pushes to the current branch on origin."
  ]
}

